(function(){"use strict";function pageType(){var b=document.body;if(b&&b.getAttribute("data-page"))return b.getAttribute("data-page");if(window.WG_GAME&&window.WG_GAME.hash)return"game";if(window.WG_COLLECTION)return"collection";var p=location.pathname;if(p==="/"||p==="")return"home";if(/^\/(category|categories|games-catalogue)\b/.test(p))return"category";if(/^\/search\b/.test(p))return"search";return"other"}function signedIn(){try{return!!(window.wgpAuth&&typeof window.wgpAuth.isSignedIn==="function"&&window.wgpAuth.isSignedIn())}catch(e){return false}}function globalParams(){var g={page_type:pageType(),signed_in:signedIn()};if(window.WG_GAME&&window.WG_GAME.hash){g.game_hash=window.WG_GAME.hash;if(window.WG_GAME.slug)g.game_slug=window.WG_GAME.slug}return g}function track(eventName,params){if(!eventName||typeof window.gtag!=="function")return;var merged=globalParams();if(params){for(var k in params){if(!Object.prototype.hasOwnProperty.call(params,k))continue;var v=params[k];if(v!==void 0&&v!==null&&v!=="")merged[k]=v}}try{window.gtag("event",eventName,merged)}catch(e){}}function norm(s){return String(s==null?"":s).replace(/\s+/g," ").trim().slice(0,80)}function className(el){var c=el.className;if(c&&typeof c==="object"&&"baseVal"in c)c=c.baseVal;return String(c||"")}function deriveLabel(el){var dt=el.getAttribute("data-track");if(dt&&dt!=="-"&&dt!=="off")return norm(dt);if(el.id)return norm(el.id);var aria=el.getAttribute("aria-label");if(aria)return norm(aria);var txt=(el.textContent||"").trim();if(txt)return norm(txt);return norm(className(el).split(/\s+/)[0])||"unknown"}function deriveSection(el){var s=el.closest("[data-section]");if(s)return norm(s.getAttribute("data-section"));var modal=el.closest('.modal[id], [data-modal], [role="dialog"]');if(modal&&modal.id)return norm(modal.id);var land=el.closest('header,nav,main,aside,footer,section[id],[role="navigation"],[role="region"]');if(land)return norm(land.id||land.tagName.toLowerCase());return"page"}var SEL='a[href], button, [role="button"], [data-track]';document.addEventListener("click",function(e){if(!e.target||!e.target.closest)return;var el=e.target.closest(SEL);if(!el)return;var dt=el.getAttribute("data-track");if(dt==="-"||dt==="off"||el.hasAttribute("data-no-autotrack"))return;var tag=el.tagName.toLowerCase();track("ui_click",{label:deriveLabel(el),section:deriveSection(el),control:el.getAttribute("role")==="button"?"role-button":tag,href:tag==="a"?el.getAttribute("href")||void 0:void 0})},true);document.addEventListener("click",function(e){if(!e.target||!e.target.closest)return;var el=e.target.closest('.rail-item[id$="RailBtn"], [id$="RailBtn"]');if(!el||!el.id)return;var rail=el.id.replace(/RailBtn$/,"").toLowerCase();track("rail_open",{rail})},true);document.addEventListener("click",function(e){if(!e.target||!e.target.closest)return;var el=e.target.closest("[data-genre], [data-period], [data-sort], [data-view]");if(!el)return;var section=deriveSection(el);if(el.hasAttribute("data-view")){track("view_mode_change",{view:el.getAttribute("data-view"),surface:section});return}var type=el.hasAttribute("data-genre")?"genre":el.hasAttribute("data-period")?"period":"sort";var value=el.getAttribute("data-genre")||el.getAttribute("data-period")||el.getAttribute("data-sort");track("filter_apply",{filter_type:type,value:norm(value),surface:section})},true);document.addEventListener("wgp:modal:open",function(e){track("modal_open",{modal:e.detail&&e.detail.id})});document.addEventListener("wgp:modal:close",function(e){track("modal_close",{modal:e.detail&&e.detail.id})});window.wgpTrack={track,pageType,view:function(name,extra){var p={view:name};if(extra){for(var k in extra)if(Object.prototype.hasOwnProperty.call(extra,k))p[k]=extra[k]}track("virtual_view",p)}}})();
